mapper.select:
SELECT * FROM es_sync_failure
WHERE entity_type = #{entityType}
  AND entity_id = #{entityId}
  AND operation = #{operation}
  AND status IN ('PENDING', 'FAILED')
ORDER BY updated_at DESC
LIMIT 1

mapper.update:
UPDATE es_sync_failure
SET status = 'SUCCESS', updated_at = NOW()
WHERE id = #{id}

UPDATE es_sync_failure
SET status = 'FAILED', error_message = #{errorMessage}, retry_count = #{retryCount}, updated_at = NOW()
WHERE id = #{id}
